const input = $input.first().json;
const query = input.query || '';

if (!query) {
  return [{ json: { error: 'No search query provided' } }];
}

// First try direct page lookup
try {
  const summary = await helpers.httpRequest({
    method: 'GET',
    url: 'https://en.wikipedia.org/api/rest_v1/page/summary/' + encodeURIComponent(query),
    returnFullResponse: true
  });

  if (summary.statusCode === 200) {
    const data = typeof summary.body === 'string' ? JSON.parse(summary.body) : summary.body;
    return [{ json: {
      title: data.title,
      summary: data.extract,
      url: data.content_urls.desktop.page
    } }];
  }
} catch (e) {
  // Direct lookup failed, try search
}

// Search Wikipedia
try {
  const search = await helpers.httpRequest({
    method: 'GET',
    url: 'https://en.wikipedia.org/w/api.php?action=query&list=search&srsearch=' + encodeURIComponent(query) + '&format=json&srlimit=3'
  });

  const results = search.query && search.query.search;
  if (!results || results.length === 0) {
    return [{ json: { error: 'No Wikipedia articles found for: ' + query } }];
  }

  // Fetch summary of the first search result
  const topTitle = results[0].title;
  const summary = await helpers.httpRequest({
    method: 'GET',
    url: 'https://en.wikipedia.org/api/rest_v1/page/summary/' + encodeURIComponent(topTitle)
  });

  return [{ json: {
    title: summary.title,
    summary: summary.extract,
    url: summary.content_urls.desktop.page
  } }];
} catch (e) {
  return [{ json: { error: 'Wikipedia API error: ' + e.message } }];
}
